
import { ref, defineComponent, reactive, toRefs } from "vue";
import { updatePersonInfo } from "../../../server/http/api/Amultitasking";

export default defineComponent({
  props: ["rowData", "team"],
  setup(props: any, ctx: any) {
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const formRef = ref();
    const formState = reactive({
      inspector: [],
      recorder: [],
      reviewer: [],
      reportProducer: [],
    });
    const rules = {
      inspector: [
        {
          required: true,
          message: "请输入检测人",
          trigger: "blur",
          type: "array",
        },
      ],
      recorder: [
        {
          required: true,
          message: "请输入记录人",
          trigger: "blur",
          type: "array",
        },
      ],
      reviewer: [
        {
          required: true,
          message: "请输入复核人",
          trigger: "blur",
          type: "array",
        },
      ],
      reportProducer: [
        {
          required: true,
          message: "请输入报告制作人",
          trigger: "blur",
          type: "array",
        },
      ],
    };

    const showModal = (rowData: any) => {
      formState.inspector =
        rowData.inspector === null ? [] : rowData.inspector.split(",");
      formState.recorder =
        rowData.recorder === null ? [] : rowData.recorder.split(",");
      formState.reviewer =
        rowData.reviewer === null ? [] : rowData.reviewer.split(",");
      formState.reportProducer =
        rowData.reportProducer === null
          ? []
          : rowData.reportProducer.split(",");
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;

          let form = {
            // code: props.rowData.taskCode,
            taskId: props.rowData.taskId,
            inspector: formState.inspector.join(","),
            recorder: formState.recorder.join(","),
            reviewer: formState.reviewer.join(","),
            reportProducer: formState.reportProducer.join(","),
          };
          updatePersonInfo(form).then((res: any) => {
            // init

            formState.inspector = [];
            formState.recorder = [];
            formState.reviewer = [];
            formState.reportProducer = [];

            visible.value = false;
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          console.log("error", error);
        });
      confirmLoading.value = true;
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,

      formState,
      formRef,
      rules,
    };
  },
});
