import { reactive, toRaw, watch } from "vue";
import { getTime } from '../../../utils/setData'


const data: any = reactive({
  formState: {
    taskCode: "",
    sampleName: "",

  }

});

export function Completetest(props: any, ctx: any) {
  let timer: any;
  watch(data.formState, (newval, o) => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      let form: any = {}
      Object.assign(form, toRaw(newval))
      ctx.emit('filterCompletetest', form)
    }, 600)

  }, {
    immediate: true
  })
  return {
    data,

  }

}