import { Starttest } from "./AmultitaskingSearch/Starttest";
import { Completetest } from "./AmultitaskingSearch/Completetest";
export default defineComponent({
  props: ["type"],
  setup(props, ctx) {
    const type = props.type;
    if (type === "任务领取") {
      let data = Taskacceptance(props, ctx);
      return {
        ...data,
      };
    }
    if (type === "领样") {
      let data = Collarsample(props, ctx);
      return {
        ...data,
      };
    }
    if (type === "试验开始") {
      let data = Starttest(props, ctx);
      return {
        ...data,
      };
    }

    if (type === "试验完成") {
      let data = Completetest(props, ctx);
      return {
        ...data,
      };
    }

