
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";
import { defineComponent } from "vue";
import {
  Taskacceptance,
  Taskacceptancecolumns,
} from "./AmultitaskingTable/Taskacceptance";
import { Collarsample } from "./AmultitaskingTable/Collarsample";
import { Starttest } from "./AmultitaskingTable/Starttest";
import { Completetest } from "./AmultitaskingTable/Completetest";
import base from "@/utils/base64";
import Graborders from "./modal/Graborders.vue";
import CollarsampleModal from "./modal/Collarsample.vue";
import TaskState from "./TaskState.vue";
import UpdateGraborders from "./modal/UpdateGraborders.vue";
export default defineComponent({
  props: ["type", "dataList", "formState"],
  components: {
    Graborders,
    CollarsampleModal,
    TaskState,
    SmileOutlined,
    DownOutlined,
    UpdateGraborders,
  },
  setup(props, ctx) {
    const type = props.type;
    if (type === "任务领取") {
      let options = Taskacceptance(props, ctx);
      return {
        ...options,
        Taskacceptancecolumns,
      };
    }
    if (type === "领样") {
      let options = Collarsample(props, ctx);
      return {
        ...options,
        base,
      };
    }
    if (type === "试验开始") {
      let options = Starttest(props, ctx);
      return {
        ...options,
      };
    }
    if (type === "试验完成") {
      let options = Completetest(props, ctx);
      return {
        ...options,
      };
    }
  },
});
