
import { ref, defineComponent, reactive, toRefs, inject, onMounted } from "vue";
import { receiveSample } from "../../../server/http/api/Amultitasking";
import { getTime } from "@/utils/setData";
import { currentTime } from "@/utils/currentTime";

export default defineComponent({
  props: ["rowData"],
  setup(props: any, ctx: any) {
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const formState: any = reactive({
      taskId: "",
      sampler: "",
      sampleReceivingTime: null,
    });
    const updateCollarsample: any = inject("updateCollarsample");
    const showModal = (rowData: any) => {
      formState.sampleReceivingTime = currentTime();
      visible.value = true;
    };

    const handleOk = () => {
      
      confirmLoading.value = true;
      let form = {
        taskId: props.rowData.taskId,
        sampler: formState.sampler,
        sampleReceivingTime: getTime(formState.sampleReceivingTime),
      };

      receiveSample(form).then((res: any) => {
        if (res.data.code === 200) {
          updateCollarsample();
        }
        // init

        visible.value = false;
        confirmLoading.value = false;
        formState.taskId = "";
        formState.sampler = "";
        formState.sampleReceivingTime = null;
      });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      ...toRefs(formState),
    };
  },
});
