import { reactive, toRaw, watch } from "vue";
import { getTime } from '../../../utils/setData'

const options = [
  {
    label: "未分配",
    value: 0,
  },
  {
    label: "已分配",
    value: 1,
  },
  {
    label: "已领样",
    value: 2,
  },
];
const data: any = reactive({
  formState: {
    taskCode: "",
    sampleName: "",
    state: 0,
  }

});

export function Taskacceptance(props: any, ctx: any) {
  let timer: any;
  watch(data.formState, (newval, o) => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      let form: any = {}
      Object.assign(form, toRaw(newval))
      // if (newval.dateInterval && newval.dateInterval.length == 2) {
      //   form.dateInterval = getTime(newval.dateInterval[0]) + '~' + getTime(newval.dateInterval[1])
      // } else {
      //   form.dateInterval = null
      // }
      ctx.emit('filterTaskacceptance', form)
    }, 600)

  }, {
    immediate: true
  })
  return {
    data,
    options,
  }

}