import { reactive, toRaw, watch } from "vue";
import { getTime } from '../../../utils/setData'


const data: any = reactive({
  formState: {
    taskCode: "",
    sampleName: "",
    receiveTime: null,

  }

});

export function Collarsample(props: any, ctx: any) {
  let timer: any;
  watch(data.formState, (newval, o) => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      let form: any = {}
      Object.assign(form, toRaw(newval))
      if (newval.receiveTime && newval.receiveTime.length == 2) {
        form.receiveTime = getTime(newval.receiveTime[0]) + '~' + getTime(newval.receiveTime[1])
      } else {
        form.receiveTime = null
      }
      ctx.emit('filterCollarsample', form)
    }, 600)

  }, {
    immediate: true
  })
  return {
    data,

  }

}